class Solution:
    def largestInteger(self, num: int) -> int:
        num_str = str(num)
        odd = []
        even = []

        for digit in num_str:
            if int(digit) % 2 == 0:
                even.append(digit)
            else:
                odd.append(digit)

        odd.sort(reverse=True)
        even.sort(reverse=True)

        result = []
        odd_idx, even_idx = 0, 0

        for digit in num_str:
            if int(digit) % 2 == 0:
                result.append(even[even_idx])
                even_idx += 1
            else:
                result.append(odd[odd_idx])
                odd_idx += 1

        return int(''.join(result))
